package main

import (
	"sort"
)

type UnionFind struct {
	parent []int
	rank   []int
}

func NewUnionFind(size int) *UnionFind {
	uf := &UnionFind{
		parent: make([]int, size),
		rank:   make([]int, size),
	}
	for i := 0; i < size; i++ {
		uf.parent[i] = i
		uf.rank[i] = 0
	}
	return uf
}

func (uf *UnionFind) Find(u int) int {
	if uf.parent[u] != u {
		uf.parent[u] = uf.Find(uf.parent[u])
	}
	return uf.parent[u]
}

func (uf *UnionFind) Union(u, v int) bool {
	rootU := uf.Find(u)
	rootV := uf.Find(v)
	if rootU == rootV {
		return false
	}

	if uf.rank[rootU] > uf.rank[rootV] {
		uf.parent[rootV] = rootU
	} else if uf.rank[rootU] < uf.rank[rootV] {
		uf.parent[rootU] = rootV
	} else {
		uf.parent[rootV] = rootU
		uf.rank[rootU]++
	}
	return true
}

func solve(n int64, edges [][]int64, k int64) int64 {
	// Convert edges to a slice of slices for easier sorting
	edgeList := make([][]int64, len(edges))
	for i, edge := range edges {
		edgeList[i] = []int64{edge[0], edge[1], edge[2]}
	}

	// Sort edges by weight
	sort.Slice(edgeList, func(i, j int) bool {
		return edgeList[i][2] < edgeList[j][2]
	})

	uf := NewUnionFind(int(n))
	components := int(n)
	var result int64 = 0

	for _, edge := range edgeList {
		if components <= int(k) {
			break
		}
		u := int(edge[0])
		v := int(edge[1])
		w := edge[2]
		if uf.Find(u) != uf.Find(v) {
			uf.Union(u, v)
			components--
			result = w
		}
	}

	return result
}
